import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Employee Management","description":"","frontmatter":{},"headers":[],"relativePath":"modules/employees.md","filePath":"modules/employees.md"}'),l={name:"modules/employees.md"};function i(d,e,n,s,p,h){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="employee-management" tabindex="-1">Employee Management <a class="header-anchor" href="#employee-management" aria-label="Permalink to &quot;Employee Management&quot;">​</a></h1><p>The Employee Management module is the core of GeniusHRM. It provides a centralised repository for all employee records, covering personal information, employment details, documents, and a full history of changes. Every other module — payroll, attendance, leave, performance — links back to this module.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The employee list is accessible at <strong>HR Panel → Employees</strong> or <code>/employees</code>. It displays all active employees with key details at a glance: employee ID, name, department, position, and employment status.</p><hr><h2 id="employee-id-format" tabindex="-1">Employee ID Format <a class="header-anchor" href="#employee-id-format" aria-label="Permalink to &quot;Employee ID Format&quot;">​</a></h2><p>Every new employee is automatically assigned a unique, sequential employee ID in the format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EMP-001</span></span>
<span class="line"><span>EMP-002</span></span>
<span class="line"><span>EMP-003</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>EMP-999</span></span>
<span class="line"><span>EMP-1000</span></span></code></pre></div><p>The prefix <code>EMP-</code> is configurable in <strong>Settings → General → Employee ID Prefix</strong>. The numeric part is auto-incremented and cannot be manually set to a value already in use.</p><div class="tip custom-block"><p class="custom-block-title">Custom Prefixes</p><p>You can use department-specific prefixes by adjusting the prefix before creating employees for each batch. For example, <code>DEV-</code> for Development team employees.</p></div><hr><h2 id="employment-status-types" tabindex="-1">Employment Status Types <a class="header-anchor" href="#employment-status-types" aria-label="Permalink to &quot;Employment Status Types&quot;">​</a></h2><p>Each employee record carries an employment status:</p><table tabindex="0"><thead><tr><th>Status</th><th>Description</th></tr></thead><tbody><tr><td><strong>Active</strong></td><td>Currently employed and working</td></tr><tr><td><strong>On Leave</strong></td><td>Temporarily away (e.g., maternity leave, extended sick leave)</td></tr><tr><td><strong>Suspended</strong></td><td>Employment temporarily suspended pending investigation</td></tr><tr><td><strong>Terminated</strong></td><td>Employment has ended</td></tr><tr><td><strong>Probation</strong></td><td>Recently hired and within the probationary period</td></tr><tr><td><strong>Contract</strong></td><td>On a fixed-term contract</td></tr></tbody></table><p>Statuses affect what the employee can access in self-service, whether they appear in payroll runs, and how they are counted in headcount reports.</p><hr><h2 id="adding-a-new-employee" tabindex="-1">Adding a New Employee <a class="header-anchor" href="#adding-a-new-employee" aria-label="Permalink to &quot;Adding a New Employee&quot;">​</a></h2><h3 id="step-1-open-the-add-employee-form" tabindex="-1">Step 1: Open the Add Employee Form <a class="header-anchor" href="#step-1-open-the-add-employee-form" aria-label="Permalink to &quot;Step 1: Open the Add Employee Form&quot;">​</a></h3><p>Click <strong>Add Employee</strong> (top right of the Employees list).</p><h3 id="step-2-fill-in-personal-information" tabindex="-1">Step 2: Fill in Personal Information <a class="header-anchor" href="#step-2-fill-in-personal-information" aria-label="Permalink to &quot;Step 2: Fill in Personal Information&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>First Name</td><td>Yes</td><td>Legal first name</td></tr><tr><td>Last Name</td><td>Yes</td><td>Legal last name</td></tr><tr><td>Email</td><td>Yes</td><td>Must be unique; used for login if linked to a user account</td></tr><tr><td>Phone</td><td>No</td><td>Mobile or office phone</td></tr><tr><td>Date of Birth</td><td>No</td><td>Used for age calculations</td></tr><tr><td>Gender</td><td>No</td><td>Male / Female / Other / Prefer Not to Say</td></tr><tr><td>National ID</td><td>No</td><td>Government-issued ID number</td></tr><tr><td>Address</td><td>No</td><td>Home address (street, city, state, country, postal code)</td></tr><tr><td>Emergency Contact</td><td>No</td><td>Name and phone number of next of kin</td></tr><tr><td>Profile Photo</td><td>No</td><td>Portrait photo (JPG/PNG, max 2 MB)</td></tr></tbody></table><h3 id="step-3-employment-details" tabindex="-1">Step 3: Employment Details <a class="header-anchor" href="#step-3-employment-details" aria-label="Permalink to &quot;Step 3: Employment Details&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>Department</td><td>Yes</td><td>Select from existing departments</td></tr><tr><td>Position</td><td>Yes</td><td>Filtered by selected department</td></tr><tr><td>Reporting Manager</td><td>No</td><td>Direct supervisor (another employee)</td></tr><tr><td>Hire Date</td><td>Yes</td><td>Official first working day</td></tr><tr><td>Employment Type</td><td>Yes</td><td>Full-time / Part-time / Contract / Intern</td></tr><tr><td>Probation End Date</td><td>No</td><td>Date probation period concludes</td></tr><tr><td>Contract End Date</td><td>No</td><td>For fixed-term employees</td></tr><tr><td>Work Location</td><td>No</td><td>Office / Remote / Hybrid</td></tr><tr><td>Employee ID</td><td>Auto</td><td>Generated automatically; can be overridden</td></tr></tbody></table><h3 id="step-4-save" tabindex="-1">Step 4: Save <a class="header-anchor" href="#step-4-save" aria-label="Permalink to &quot;Step 4: Save&quot;">​</a></h3><p>Click <strong>Save Employee</strong>. The system:</p><ol><li>Creates the employee record</li><li>Assigns the next available Employee ID</li><li>Records the creation in the Employment History log</li><li>Records the event in the Audit Log</li><li>Optionally creates a linked User account if email is provided</li></ol><hr><h2 id="employee-profile" tabindex="-1">Employee Profile <a class="header-anchor" href="#employee-profile" aria-label="Permalink to &quot;Employee Profile&quot;">​</a></h2><p>Each employee has a detailed profile page at <code>/employees/{id}</code>. The profile is organised into tabs:</p><h3 id="overview-tab" tabindex="-1">Overview Tab <a class="header-anchor" href="#overview-tab" aria-label="Permalink to &quot;Overview Tab&quot;">​</a></h3><p>Displays all basic information:</p><ul><li>Personal details (name, DOB, gender, contact)</li><li>Employment details (department, position, type, dates)</li><li>Profile photo</li><li>Current employment status badge</li><li>Reporting manager link</li></ul><h3 id="documents-tab" tabindex="-1">Documents Tab <a class="header-anchor" href="#documents-tab" aria-label="Permalink to &quot;Documents Tab&quot;">​</a></h3><p>Lists all files attached to this employee:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Document Name</td><td>Filename or given label</td></tr><tr><td>Category</td><td>Contract, ID Proof, Certificate, Other</td></tr><tr><td>Uploaded At</td><td>Date of upload</td></tr><tr><td>Uploaded By</td><td>User who uploaded the file</td></tr><tr><td>Actions</td><td>Download / Delete</td></tr></tbody></table><p>To add a document:</p><ol><li>Click <strong>Upload Document</strong></li><li>Select the file (PDF, JPG, PNG, DOCX — max 10 MB)</li><li>Choose a category</li><li>Enter an optional document label</li><li>Click <strong>Upload</strong></li></ol><h3 id="history-tab" tabindex="-1">History Tab <a class="header-anchor" href="#history-tab" aria-label="Permalink to &quot;History Tab&quot;">​</a></h3><p>A chronological log of every change made to this employee&#39;s record:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Date</td><td>When the change was made</td></tr><tr><td>Changed By</td><td>The user who made the change</td></tr><tr><td>Field</td><td>Which field was changed</td></tr><tr><td>Old Value</td><td>Previous value</td></tr><tr><td>New Value</td><td>New value</td></tr></tbody></table><p>This log is auto-generated by the system and cannot be manually edited.</p><hr><h2 id="search-and-filter-options" tabindex="-1">Search and Filter Options <a class="header-anchor" href="#search-and-filter-options" aria-label="Permalink to &quot;Search and Filter Options&quot;">​</a></h2><p>The employee list supports the following search and filter controls:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td>Text</td><td>Name, email, or employee ID</td></tr><tr><td><strong>Department</strong></td><td>Dropdown</td><td>Filter by department</td></tr><tr><td><strong>Position</strong></td><td>Dropdown</td><td>Filter by position</td></tr><tr><td><strong>Status</strong></td><td>Dropdown</td><td>Active, On Leave, Suspended, Terminated, etc.</td></tr><tr><td><strong>Employment Type</strong></td><td>Dropdown</td><td>Full-time, Part-time, Contract, Intern</td></tr><tr><td><strong>Hire Date Range</strong></td><td>Date range</td><td>Filter by when employees were hired</td></tr><tr><td><strong>Gender</strong></td><td>Dropdown</td><td>Male, Female, Other</td></tr></tbody></table><p>Multiple filters can be active simultaneously. Reset all filters with the <strong>Clear</strong> button.</p><hr><h2 id="editing-an-employee" tabindex="-1">Editing an Employee <a class="header-anchor" href="#editing-an-employee" aria-label="Permalink to &quot;Editing an Employee&quot;">​</a></h2><ol><li>Click an employee&#39;s name in the list (or the Edit icon)</li><li>Modify the desired fields</li><li>Click <strong>Update Employee</strong></li></ol><p>All changes are:</p><ul><li>Logged in the employee&#39;s History tab</li><li>Recorded in the system Audit Log</li></ul><hr><h2 id="soft-delete-behaviour" tabindex="-1">Soft Delete Behaviour <a class="header-anchor" href="#soft-delete-behaviour" aria-label="Permalink to &quot;Soft Delete Behaviour&quot;">​</a></h2><p>Employees are never permanently deleted from the database. Instead, &quot;deleting&quot; an employee marks them as <strong>soft-deleted</strong>:</p><ul><li>They disappear from all active employee lists</li><li>They are excluded from payroll runs</li><li>All their historical records (attendance, payslips, leave) remain intact</li><li>They can be <strong>restored</strong> by an Admin via the <strong>Archived Employees</strong> section</li></ul><p>To archive an employee:</p><ol><li>Open their profile</li><li>Click <strong>More Actions → Archive Employee</strong></li><li>Select a <strong>Termination Date</strong> and reason</li><li>Confirm</li></ol><p>To restore a soft-deleted employee:</p><ol><li>Go to <strong>Employees → Archived</strong></li><li>Click <strong>Restore</strong> next to their name</li></ol><hr><h2 id="employment-history-auto-tracking" tabindex="-1">Employment History Auto-Tracking <a class="header-anchor" href="#employment-history-auto-tracking" aria-label="Permalink to &quot;Employment History Auto-Tracking&quot;">​</a></h2><p>The system automatically creates employment history entries for:</p><ul><li>Initial hire</li><li>Promotions (position change)</li><li>Department transfers</li><li>Status changes (e.g., Active → Suspended)</li><li>Salary changes (recorded from Payroll module)</li><li>Contract renewals</li></ul><p>Each entry records the previous and new values, the date, and the user who made the change.</p><hr><h2 id="bulk-import" tabindex="-1">Bulk Import <a class="header-anchor" href="#bulk-import" aria-label="Permalink to &quot;Bulk Import&quot;">​</a></h2><p>To import multiple employees at once:</p><ol><li>Go to <strong>Employees → Import</strong></li><li>Download the <strong>CSV Template</strong></li><li>Fill in employee data following the template format</li><li>Upload the completed CSV</li><li>Review the import preview (validation errors are highlighted)</li><li>Click <strong>Confirm Import</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The import function does not overwrite existing employees. Each row creates a new record. Duplicate email addresses are rejected.</p></div><hr><h2 id="exporting-employee-data" tabindex="-1">Exporting Employee Data <a class="header-anchor" href="#exporting-employee-data" aria-label="Permalink to &quot;Exporting Employee Data&quot;">​</a></h2><p>Click <strong>Export</strong> on the Employees list to download all currently filtered employees as a CSV file. The export includes all visible columns plus additional fields not shown in the table view.</p>`,73)])])}const y=t(l,[["render",i]]);export{c as __pageData,y as default};
